void ProcessDialogEvent(){	ref NPChar;	aref Link, NextDiag;	DeleteAttribute(&Dialog, "Links");	makeref(NPChar, CharacterRef);	makearef(Link, Dialog.Links);	makearef(NextDiag, NPChar.Dialog);	switch (Dialog.CurrentNode)	{		case "first time":			dialog.text = StringFromKey("Fushe_sailor_1");			link.l1 = StringFromKey("Fushe_sailor_2");			link.l1.go = "1";		break;		case "1":			dialog.text = StringFromKey("Fushe_sailor_3");			link.l1 = StringFromKey("Fushe_sailor_4");			link.l1.go = "2";		break;		case "2":			dialog.text = StringFromKey("Fushe_sailor_5");			link.l1 = StringFromKey("Fushe_sailor_6");			link.l1.go = "3";		break;		case "3":			dialog.text = StringFromKey("Fushe_sailor_7");			link.l1 = StringFromKey("Fushe_sailor_8");			link.l1.go = "4";		break;		case "4":			dialog.text = StringFromKey("Fushe_sailor_9");			link.l1 = StringFromKey("Fushe_sailor_10");			link.l1.go = "5";		break;		case "5":			dialog.text = StringFromKey("Fushe_sailor_11");			link.l1 = StringFromKey("Fushe_sailor_12");			link.l1.go = "exit";		break;		case "exit":			if (CheckAttribute(NextDiag, "TempNode")) NextDiag.CurrentNode = NextDiag.TempNode;			DialogExit();		break;	}}